18	#include "src/fastertransformer/kernels/reduce_kernel_utils.cuh"
19	#include "src/fastertransformer/utils/cuda_type_utils.cuh"
20	
21	namespace fastertransformer {
22	
23	// * Note that typename T is half2 or bfloat2 type
24	template<typename T, bool IS_OUTPUT, bool IS_BIAS, int RESIDUAL_NUM, bool IS_BETA, int UNROLL_FACTOR>
25	__global__ void generalAddBiasResidualLayerNormOpt(T* normed_output,
26	                                                   T* output,
27	                                                   const T* __restrict input,
28	                                                   const T* __restrict bias,
29	                                                   const T* __restrict residual1,
30	                                                   const T* __restrict residual2,
31	                                                   const T* __restrict gamma,
32	                                                   const T* __restrict beta,
33	                                                   const float  layernorm_eps,
34	                                                   int          m,
35	                                                   int          n,
36	                                                   const float* scale_inter,
37	                                                   const float* scale_out,
38	                                                   const float* scale,
39	                                                   float*       dynamic_scale,
40	                                                   const int    int8_mode)
41	{
42	    extern __shared__ __align__(sizeof(float)) char _shmem[];  // Align on largest type
43	    T*                                              shmem = reinterpret_cast<T*>(_shmem);
44	
45	    __shared__ float s_mean;
46	    __shared__ float s_variance;
47	    float            mean     = 0.0f;
48	    float            variance = 0.0f;
49	
50	    using Int8_Packed_T  = typename packed_as<int8_t, num_elems<T>::value>::type;
51	    using Int32_Packed_T = typename packed_as<int32_t, num_elems<T>::value>::type;
52	    using Float_Packed_T = typename packed_as<float, num_elems<T>::value>::type;
53	    using Scalar_T       = typename packed_as<T, 1>::type;
54	
55	    const bool scale_input     = int8_mode == 2 && scale_inter != nullptr;
56	    const bool dynamic_scaling = dynamic_scale != nullptr;
57	
58	    T local_sum = cuda_cast<T>(0.0f);
59	
60	    const Float_Packed_T scale_from_int = cuda_cast<Float_Packed_T>(scale_input ? (*scale_inter) * (*scale_out) : 0.0f);
61	    const Float_Packed_T scale_to_int   = cuda_cast<Float_Packed_T>(int8_mode == 2 ? *scale : 0.0f);
62	
63	#pragma unroll
64	    for (int i = threadIdx.x; i < n; i += blockDim.x) {
65	        const int index = blockIdx.x * n + i;
66	        T         val   = cuda_cast<T>(0.0f);
67	
68	        if (IS_BIAS) {
69	            val = hadd2(val, ldg(&bias[i]));
70	        }
71	        if (RESIDUAL_NUM == 1) {
72	            val = hadd2(val, ldg(&residual1[index]));
73	        }
74	        else if (RESIDUAL_NUM == 2) {
75	            val = hadd2(hadd2(val, ldg(&residual1[index])), ldg(&residual2[index]));
76	        }
77	
78	        if (IS_OUTPUT) {
79	            T in_val;
80	            if (scale_input) {
81	                in_val = cuda_cast<T>(cuda_cast<Float_Packed_T>(reinterpret_cast<const Int32_Packed_T*>(input)[index])
82	                                      * scale_from_int);
83	            }
84	            else {
85	                in_val = input[index];
86	            }
87	            val = hadd2(val, in_val);
88	        }
89	        shmem[i]      = val;
90	        output[index] = val;
91	        local_sum     = hadd2(local_sum, val);
92	    }
93	
94	    mean = blockReduceSum((float)(local_sum.x + local_sum.y));
95	
96	    if (threadIdx.x == 0) {
97	        s_mean = mean / n / 2;
98	    }
99	    __syncthreads();
100	
101	    float local_var_sum = 0.0f;
102	#pragma unroll UNROLL_FACTOR
103	    for (int i = threadIdx.x; i < n; i += blockDim.x) {
104	        T     val    = input[blockIdx.x * n + i];
105	        float diff_1 = (float)(val.x) - s_mean;
106	        float diff_2 = (float)(val.y) - s_mean;
107	        local_var_sum += (diff_1 * diff_1 + diff_2 * diff_2);
108	    }
109	    variance = blockReduceSum(local_var_sum);
110	
111	    if (threadIdx.x == 0) {
112	        s_variance = rsqrtf(variance / n / 2 + layernorm_eps);
113	    }
114	    __syncthreads();
115	
116	    T mean_2 = cuda_cast<T>(s_mean);
117	    T var_2  = cuda_cast<T>(s_variance);
118	
119	    Scalar_T abs_max = 1e-6f;
120	
121	#pragma unroll UNROLL_FACTOR
122	    for (int i = threadIdx.x; i < n; i += blockDim.x) {
123	        const int index = blockIdx.x * n + i;
124	        T         val   = hmul2(hsub2(shmem[i], mean_2), var_2, ldg(&gamma[i]));
125	        if (IS_BETA) {
126	            val = hadd2(val, ldg(&beta[i]));
127	        }
128	
129	        if (dynamic_scaling) {
130	            abs_max  = cuda_max(cuda_max<Scalar_T>(cuda_abs(val)), abs_max);
131	            shmem[i] = val;
132	        }
133	        else if (int8_mode == 2) {
134	            reinterpret_cast<Int8_Packed_T*>(normed_output)[index] =
135	                cuda_cast<Int8_Packed_T>(cuda_cast<Float_Packed_T>(val) * scale_to_int);
136	        }
137	        else {
138	            normed_output[index] = val;
139	        }
140	    }
141	
142	    if (dynamic_scaling) {
143	        float       abs_max_f               = blockAllReduceMax(cuda_cast<float>(abs_max));
144	        const float dynamic_per_token_scale = 127. / abs_max_f;
145	        for (int i = threadIdx.x; i < n; i += blockDim.x) {
146	            const int index                                        = blockIdx.x * n + i;
147	            reinterpret_cast<Int8_Packed_T*>(normed_output)[index] = cuda_cast<Int8_Packed_T>(
148	                cuda_cast<Float_Packed_T>(shmem[i]) * cuda_cast<Float_Packed_T>(dynamic_per_token_scale));
149	        }
150	        if (threadIdx.x == 0) {
151	            dynamic_scale[blockIdx.x] = (*scale * abs_max_f) / 127.f;
152	        }
153	    }
154	}
155	
156	// * Note that typename T is half2 or bfloat2 type
157	template<typename T, bool IS_OUTPUT, bool IS_BIAS, int RESIDUAL_NUM, bool IS_BETA, int UNROLL_FACTOR>
158	__global__ void generalAddBiasResidualLayerNormOpt2(T* normed_output,
159	                                                    T* output,
160	                                                    const T* __restrict input,
161	                                                    const T* __restrict bias,
162	                                                    const T* __restrict residual1,
163	                                                    const T* __restrict residual2,
164	                                                    const T* __restrict gamma,
165	                                                    const T* __restrict beta,
166	                                                    const float  layernorm_eps,
167	                                                    int          m,
168	                                                    int          n,
169	                                                    const float* scale_inter,
170	                                                    const float* scale_out,
171	                                                    const float* scale,
172	                                                    float*       dynamic_scale,
173	                                                    const int    int8_mode)
174	{
175	    extern __shared__ __align__(sizeof(float)) char _shmem[];
176	    T*                                              shmem = reinterpret_cast<T*>(_shmem);
177	
178	    __shared__ float s_mean;
179	    __shared__ float s_variance;
180	    float            x_sum    = 0.0f;
181	    float            x2_sum   = 0.0f;
182	    const int        b_offset = blockIdx.x * n;
183	
184	    using T1             = typename TypeConverter<T>::Type;
185	    using Int8_Packed_T  = typename packed_as<int8_t, num_elems<T>::value>::type;
186	    using Int32_Packed_T = typename packed_as<int32_t, num_elems<T>::value>::type;
187	    using Float_Packed_T = typename packed_as<float, num_elems<T>::value>::type;
188	    using Scalar_T       = typename packed_as<T, 1>::type;
189	
190	    const bool           scale_input  = int8_mode == 2 && scale_inter != nullptr;
191	    const Float_Packed_T scale_vec_in = cuda_cast<Float_Packed_T>(scale_input ? (*scale_inter) * (*scale_out) : 0.0f);
192	    const Float_Packed_T scale_vec    = cuda_cast<Float_Packed_T>(int8_mode == 2 ? *scale : 0.0f);
193	    const bool           dynamic_scaling = dynamic_scale != nullptr;
194	
195	#pragma unroll UNROLL_FACTOR
196	    for (int i = threadIdx.x; i < n; i += blockDim.x) {
197	        const int index = b_offset + i;
198	        float     val_1 = 0.0f;
199	        float     val_2 = 0.0f;
200	        T         tmp;
201	
202	        if (IS_BIAS) {
203	            tmp = ldg(&bias[i]);
204	            val_1 += static_cast<float>(tmp.x);
205	            val_2 += static_cast<float>(tmp.y);
206	        }
207	        if (RESIDUAL_NUM == 1) {
208	            tmp = ldg(&residual1[index]);
209	            val_1 += static_cast<float>(tmp.x);
210	            val_2 += static_cast<float>(tmp.y);
211	        }
212	        else if (RESIDUAL_NUM == 2) {
213	            tmp    = ldg(&residual1[index]);
214	            T tmp2 = ldg(&residual2[index]);
215	            val_1 += (static_cast<float>(tmp.x) + static_cast<float>(tmp2.x));
216	            val_2 += (static_cast<float>(tmp.y) + static_cast<float>(tmp2.y));
217	        }
218	
219	        if (IS_OUTPUT) {
220	            if (scale_input) {
221	                tmp = cuda_cast<T>(cuda_cast<Float_Packed_T>(reinterpret_cast<const Int32_Packed_T*>(input)[index])
222	                                   * scale_vec_in);
223	            }
224	            else {
225	                tmp = ldg(&input[index]);
226	            }
